import { useState } from "react";
import { ethers } from "ethers";

export default function VerifyCertificate({ contractAddress, abi }) {
  const [searchId, setSearchId] = useState("");
  const [certData, setCertData] = useState(null);
  const [loading, setLoading] = useState(false);

  async function handleVerify() {
    setLoading(true);
    try {
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const contract = new ethers.Contract(contractAddress, abi, provider);

      const certIdBytes = ethers.utils.formatBytes32String(searchId);
      
      const data = await contract.verify(certIdBytes);

      if (data[3] === true) { // data[3] is the 'isValid' boolean from Solidity
        setCertData({
          name: data[0],
          course: data[1],
          ipfs: data[2]
        });
      } else {
        alert("Certificate not found or invalid!");
        setCertData(null);
      }
    } catch (error) {
      console.error(error);
      alert("Error verifying certificate. Check the ID.");
    }
    setLoading(false);
  }

  return (
    <div className="card">
      <h3>Verify a Certificate</h3>
      <input 
        placeholder="Enter Certificate ID (e.g. CERT001)" 
        onChange={e => setSearchId(e.target.value)} 
      />
      <button onClick={handleVerify} disabled={loading}>
        {loading ? "Verifying..." : "Search Blockchain"}
      </button>

      {certData && (
        <div style={{ marginTop: "20px", border: "1px solid #ccc", padding: "10px" }}>
          <h4>✅ Authenticity Verified</h4>
          <p><strong>Student Name:</strong> {certData.name}</p>
          <p><strong>Course:</strong> {certData.course}</p>
          <p><strong>IPFS Hash:</strong> {certData.ipfs}</p>
          <a href={`https://ipfs.io/ipfs/${certData.ipfs}`} target="_blank" rel="noreferrer">
            View Original Document
          </a>
        </div>
      )}
    </div>
  );
}
